tailwind_theme_snippet:
/* app/globals.css — Tailwind 4 @theme block. Paste after @import 'tailwindcss'; */
@import 'tailwindcss';

@theme {
  /* Colors */
  --color-primary: #0B0B0C;
  --color-surface: #121214;
  --color-surface-elevated: #17171A;
  --color-text: #EDEAE3;
  --color-text-muted: #8A857A;
  --color-text-dim: #53504A;
  --color-accent: #E8A44C;
  --color-accent-muted: #A87534;
  --color-border: #26252A;
  --color-border-strong: #36343B;

  /* Fonts — bound to next/font CSS variables */
  --font-display: var(--font-fraunces);
  --font-sans: var(--font-geist);
  --font-mono: var(--font-jetbrains-mono);

  /* Type scale */
  --text-display-xl: clamp(3.5rem, 8vw + 1rem, 7.5rem);
  --text-display: clamp(2.5rem, 5vw + 1rem, 5rem);
  --text-h1: clamp(2rem, 3vw + 1rem, 3.25rem);
  --text-h2: clamp(1.5rem, 2vw + 0.75rem, 2.25rem);

  /* Container */
  --spacing-container: 1100px;

  /* Easing */
  --ease-out-expo: cubic-bezier(0.2, 0.8, 0.2, 1);
}

/* Base layer */
@layer base {
  html { color-scheme: dark; scroll-behavior: smooth; }
  body {
    background: var(--color-primary);
    color: var(--color-text);
    font-family: var(--font-sans), ui-sans-serif, system-ui, sans-serif;
    font-feature-settings: 'ss01', 'cv11';
    -webkit-font-smoothing: antialiased;
  }
  ::selection { background: rgba(232, 164, 76, 0.25); color: var(--color-text); }
  :focus-visible { outline: 2px solid var(--color-accent); outline-offset: 3px; border-radius: 4px; }
  [id] { scroll-margin-top: 80px; }
  h1, h2, h3 { font-family: var(--font-display), ui-serif, Georgia, serif; letter-spacing: -0.035em; line-height: 0.95; font-variation-settings: 'opsz' 144; }
  em { font-style: italic; font-variation-settings: 'opsz' 144, 'WONK' 1; }
  .eyebrow { font-family: var(--font-mono), ui-monospace, monospace; font-size: 0.8125rem; letter-spacing: 0.04em; text-transform: uppercase; color: var(--color-text-muted); }
}

/* Staggered reveal */
@keyframes reveal-up {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}
.reveal { animation: reveal-up 420ms var(--ease-out-expo) both; animation-delay: calc(var(--reveal-i, 0) * 80ms); }

/* Index row hover underline */
.index-row .name-link {
  background-image: linear-gradient(var(--color-accent), var(--color-accent));
  background-size: 0% 1px;
  background-repeat: no-repeat;
  background-position: 0 100%;
  transition: background-size 220ms var(--ease-out-expo);
}
.group\/row:hover .name-link,
.group\/row:focus-visible .name-link { background-size: 100% 1px; }

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after { animation-duration: 0.01ms !important; animation-iteration-count: 1 !important; transition-duration: 0.01ms !important; scroll-behavior: auto !important; }
  .index-row .name-link { transition: none; }
}
